# Create a system restore point# Relaunches itself as Administrator if needed$isAdmin = ([Security.Principal.WindowsPrincipal][Security.Principal.WindowsIdentity]::GetCurrent()           ).IsInRole([Security.Principal.WindowsBuiltInRole]::Administrator)if (-not $isAdmin) {    Start-Process powershell.exe -ArgumentList "-ExecutionPolicy Bypass -File `"$PSCommandPath`"" -Verb RunAs    exit}try {    # Bypass the 24h frequency limit    $regPath = "HKLM:\SOFTWARE\Microsoft\Windows NT\CurrentVersion\SystemRestore"    Set-ItemProperty -Path $regPath -Name "SystemRestorePointCreationFrequency" -Value 0 -Type DWord -ErrorAction SilentlyContinue    # Enable System Restore for C: if disabled    Enable-ComputerRestore -Drive "C:\" -ErrorAction SilentlyContinue    # Create restore point    Checkpoint-Computer -Description "FluentCleaner - Before Clean" -RestorePointType "MODIFY_SETTINGS"    Write-Host "Restore point created successfully."}catch {    Write-Host "Failed: $($_.Exception.Message)"    exit 1}